import redis

class CacheService:
    def __init__(self, host='localhost', port=6379, db=0):
        self.connection = redis.Redis(host=host, port=port, db=db)

    def set_with_ttl(self, key, value, ttl):
        return self.connection.setex(key, time=ttl, value=value)

    def get(self, key):
        return self.connection.get(key)

    def delete(self, key):
        return self.connection.delete(key)

# Example usage
if __name__ == "__main__":
    cache = CacheService(host='your-redis-host', port=6379, db=0)
    
    # Storing a session token with a TTL of 3600 seconds (1 hour)
    session_token = "user_session_token_123"
    ttl_seconds = 3600
    cache.set_with_ttl('session_token', session_token, ttl_seconds)

    # Retrieving the session token
    retrieved_token = cache.get('session_token')
    print("Retrieved Session Token:", retrieved_token.decode())

    # Deleting the session token
    deleted_count = cache.delete('session_token')
    print("Deleted Count:", deleted_count)